// CONVERSION_EVENTS are weighted heavier because match quality matters most for
// the events you optimize on. ALERT_BELOW is the score that triggers an alert.
//
// DATASET_IDS: leave empty [] to auto-discover and surface EVERY active pixel/
// dataset on the account, or list specific IDs to monitor only those.
return [{ json: {
  DATASET_IDS: [],         // e.g. ['YOUR_DATASET_ID_1', 'YOUR_DATASET_ID_2'] to pick specific datasets
  PIXEL_LIMIT: 50,         // max pixels to check when auto-discovering
  ACTIVE_DAYS: 14,         // when auto-discovering, only score pixels fired within this many days
  ALERT_BELOW: 70,         // score under this = alert
  CONVERSION_EVENTS: ['SubmitApplication', 'Lead', 'Purchase', 'CompleteRegistration', 'Optin-Start', 'Subscribe', 'StartTrial', 'AddPaymentInfo'],
} }];

// Ask Claude to explain the biggest match-quality gaps and how to fix them.
const { pixels, cfg } = $json;
const worst = pixels.filter((p) => p.score !== null && p.score < cfg.ALERT_BELOW);
const system = 'You are a server-side tracking specialist. You are given Meta pixel event match-quality data (PII coverage per event; conversion events matter most). For each low-scoring pixel, explain the risk in one line and give one concrete fix (e.g. add hashed email/phone to CAPI payloads, pass fbc/fbp, enable Advanced Matching). Be specific and terse. Return ONLY valid JSON.';
const user = 'Alert threshold: ' + cfg.ALERT_BELOW + '. Pixels:\n' + JSON.stringify(pixels) + '\n\nReturn JSON exactly: {"summary":"one sentence","pixels":[{"name":"","score":0,"risk":"","fix":""}]}';
const body = { model: 'claude-haiku-4-5', max_tokens: 1200, system, messages: [{ role: 'user', content: user }] };
return [{ json: { body, _ctx: $json } }];

// Print the EMQ scorecard and AI recommendations to stdout.
const ctx = $node['Score event match quality per pixel'].json;
const raw = ($json.content && $json.content[0] && $json.content[0].text) || '{}';
const s = raw.indexOf('{'), e = raw.lastIndexOf('}');
let parsed = { summary: '', pixels: [] };
try { parsed = JSON.parse(raw.slice(s, e + 1)); } catch (err) {}
const fixOf = {}; (parsed.pixels || []).forEach((p) => { fixOf[p.name] = p; });

const out = [];
out.push('');
out.push('==========================================================');
out.push('  META CAPI EVENT MATCH QUALITY MONITOR  |  nocode.expert');
out.push('==========================================================');
out.push(parsed.summary || '');
out.push('Pixels checked: ' + ctx.checked + '   |   Alert below: ' + ctx.cfg.ALERT_BELOW);
out.push('');
for (const p of ctx.pixels) {
  const flag = p.score !== null && p.score < ctx.cfg.ALERT_BELOW ? '  <-- ALERT' : '';
  out.push('[' + (p.score === null ? ' n/a' : String(p.score).padStart(3)) + '/100] ' + p.name + flag);
  const conv = p.events.filter((x) => x.is_conversion);
  for (const c of conv.slice(0, 3)) out.push('        ' + c.name + ': ' + c.pii_pct + '% PII on ' + c.events + ' events');
  const f = fixOf[p.name];
  if (f && f.fix) out.push('        FIX: ' + f.fix);
}
out.push('==========================================================');
console.log(out.join('\n'));
return [{ json: { scorecard: ctx.pixels, summary: parsed.summary } }];

const cfg = $('Set config: conversion events, alert threshold').first().json;
const now = Date.now();
const list = $json.data || [];
let active;
if (Array.isArray(cfg.DATASET_IDS) && cfg.DATASET_IDS.length) {
  const want = new Set(cfg.DATASET_IDS.map(String));
  active = list.filter(p => want.has(String(p.id)));
} else {
  active = list.filter(p => p.last_fired_time && (now - new Date(p.last_fired_time).getTime()) < cfg.ACTIVE_DAYS*864e5).slice(0, cfg.PIXEL_LIMIT);
}
return active.map(p => ({ json: { id: p.id, name: p.name } }));

const cfg = $('Set config: conversion events, alert threshold').first().json;
const pixelsMeta = $('Select active pixels').all();
const CONV = new Set(cfg.CONVERSION_EVENTS);
const responses = $input.all();
const pixels = [];
responses.forEach((item, i) => {
  const p = pixelsMeta[i].json;
  const rows = (((item.json.data||[{}])[0]||{}).data) || [];
  const ev = {};
  for (const r of rows) { const e = (ev[r.event] = ev[r.event] || { has:0, total:0 }); const c = Number(r.count)||0; e.total += c; if (r.value==='has_pii') e.has += c; }
  const events = Object.entries(ev).map(([name,c]) => ({ name, events:c.total, pii_pct: c.total? Math.round(100*c.has/c.total):0, is_conversion: CONV.has(name) })).sort((a,b)=>b.events-a.events);
  let wSum=0,wPii=0;
  for (const e of events){ const w=(e.is_conversion?3:1)*e.events; wSum+=w; wPii+=w*e.pii_pct; }
  const score = wSum? Math.round(wPii/wSum): null;
  if (events.length) pixels.push({ id:p.id, name:p.name, score, events });
});
pixels.sort((a,b)=>(a.score??101)-(b.score??101));
return [{ json: { pixels, checked: pixelsMeta.length, cfg } }];
